import{_ as a,o,c as i,ag as l}from"./chunks/framework.ByAj6Cie.js";const p=JSON.parse('{"title":"Caída de Voltaje","description":"","frontmatter":{},"headers":[],"relativePath":"es/cables/fundamentals/voltage-drop.md","filePath":"es/cables/fundamentals/voltage-drop.md"}'),r={name:"es/cables/fundamentals/voltage-drop.md"};function t(n,e,c,s,d,u){return o(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="caida-de-voltaje" tabindex="-1">Caída de Voltaje <a class="header-anchor" href="#caida-de-voltaje" aria-label="Permalink to &quot;Caída de Voltaje&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción General <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción General&quot;">​</a></h2><p>La caída de voltaje es la reducción del voltaje eléctrico a medida que la corriente fluye a través de un conductor. Ocurre debido a la resistencia inherente (y la impedancia en sistemas de corriente alterna) del cable.</p><p>En sistemas industriales, la caída de voltaje puede afectar el desempeño de los equipos, especialmente en largas distancias o aplicaciones de alta corriente.</p><hr><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Comprender la caída de voltaje es esencial para asegurar que los equipos reciban el nivel adecuado de voltaje para operar correctamente.</p><p>Una caída de voltaje excesiva puede provocar:</p><ul><li>Reducción del torque en motores</li><li>Funcionamiento incorrecto de los equipos</li><li>Incremento en el consumo de corriente</li><li>Sobrecalentamiento y menor eficiencia</li></ul><hr><h2 id="como-funciona" tabindex="-1">Cómo Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo Funciona&quot;">​</a></h2><p>A medida que la corriente fluye por un conductor, se pierde energía debido a la resistencia. Esta pérdida se manifiesta como una reducción de voltaje a lo largo del cable.</p><p>En términos simples:</p><ul><li>Cables más largos → mayor resistencia → mayor caída de voltaje</li><li>Mayor corriente → mayores pérdidas → mayor caída de voltaje</li></ul><p>En sistemas de corriente alterna (AC), la caída de voltaje también está influenciada por:</p><ul><li>Reactancia (efectos inductivos)</li><li>Factor de potencia</li></ul><p>La caída total de voltaje depende de:</p><ul><li>Longitud del cable</li><li>Corriente</li><li>Material del conductor</li><li>Área de sección transversal</li><li>Tipo de sistema (monofásico o trifásico)</li></ul><hr><h2 id="factores-clave" tabindex="-1">Factores Clave <a class="header-anchor" href="#factores-clave" aria-label="Permalink to &quot;Factores Clave&quot;">​</a></h2><h3 id="longitud-del-cable" tabindex="-1">Longitud del Cable <a class="header-anchor" href="#longitud-del-cable" aria-label="Permalink to &quot;Longitud del Cable&quot;">​</a></h3><ul><li>La caída de voltaje aumenta linealmente con la distancia</li><li>Los recorridos largos son la causa más común de caídas excesivas</li></ul><hr><h3 id="corriente" tabindex="-1">Corriente <a class="header-anchor" href="#corriente" aria-label="Permalink to &quot;Corriente&quot;">​</a></h3><ul><li>Mayor corriente genera mayor caída de voltaje</li><li>Las variaciones de carga afectan directamente el voltaje</li></ul><hr><h3 id="tamano-del-conductor" tabindex="-1">Tamaño del Conductor <a class="header-anchor" href="#tamano-del-conductor" aria-label="Permalink to &quot;Tamaño del Conductor&quot;">​</a></h3><ul><li>Conductores más grandes tienen menor resistencia</li><li>Aumentar el tamaño reduce la caída de voltaje</li></ul><hr><h3 id="material-del-conductor" tabindex="-1">Material del Conductor <a class="header-anchor" href="#material-del-conductor" aria-label="Permalink to &quot;Material del Conductor&quot;">​</a></h3><ul><li>Cobre → menor resistencia → menor caída de voltaje</li><li>Aluminio → mayor resistencia → mayor caída de voltaje</li></ul><hr><h3 id="tipo-de-sistema" tabindex="-1">Tipo de Sistema <a class="header-anchor" href="#tipo-de-sistema" aria-label="Permalink to &quot;Tipo de Sistema&quot;">​</a></h3><ul><li>Los sistemas trifásicos suelen presentar menor caída de voltaje que los monofásicos para el mismo nivel de potencia</li></ul><hr><h3 id="factor-de-potencia-sistemas-ac" tabindex="-1">Factor de Potencia (Sistemas AC) <a class="header-anchor" href="#factor-de-potencia-sistemas-ac" aria-label="Permalink to &quot;Factor de Potencia (Sistemas AC)&quot;">​</a></h3><ul><li>Un factor de potencia bajo incrementa la caída de voltaje</li><li>Cargas reactivas (motores, variadores) empeoran el efecto</li></ul><hr><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>La caída de voltaje debe considerarse en:</p><ul><li>Recorridos largos en plantas industriales</li><li>Instalaciones de motores y VFD</li><li>Sistemas de distribución eléctrica</li><li>Conexión de equipos remotos</li></ul><hr><h2 id="consideraciones-clave" tabindex="-1">Consideraciones Clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones Clave&quot;">​</a></h2><p>Al evaluar la caída de voltaje:</p><ul><li>Mantenerla dentro de límites aceptables (típicamente 3–5% según normas y aplicación)</li><li>Considerar condiciones de carga en el peor caso</li><li>Aumentar el tamaño del conductor si la caída es excesiva</li><li>Evaluar tanto condiciones en régimen como de arranque (especialmente en motores)</li><li>Considerar distancias reales de instalación, no solo planos</li></ul><hr><h2 id="notas-practicas" tabindex="-1">Notas Prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas Prácticas&quot;">​</a></h2><ul><li>La caída de voltaje suele subestimarse en diseño, pero se vuelve evidente en operación.</li><li>Los motores son especialmente sensibles a bajo voltaje, lo que incrementa la corriente y reduce su vida útil.</li><li>En sistemas con VFD, longitudes grandes de cable pueden introducir efectos adicionales más allá de la caída de voltaje.</li><li>Aumentar el tamaño del cable es la solución más común, pero debe balancearse con el costo.</li></ul>',48)])])}const h=a(r,[["render",t]]);export{p as __pageData,h as default};
